function mean(num) {
  const digits = Array.from(String(num), Number);
  const sum = digits.reduce((total, digit) => total + digit, 0);
  return Math.floor(sum / digits.length);
}
```

// Example usage:
console.log(mean(42)); // Output: 3
console.log(mean(12345)); // Output: 3
console.log(mean(666)); // Output: 6
```

```javascript
function diceGame(matrix) {
  let score = 0;
  for (let i = 0; i < matrix.length; i++) {
    const dice1 = matrix[i][0];
    const dice2 = matrix[i][1];

    if (dice1 === dice2) {
      return 0; // If doubles are rolled, instantly return 0
    }

    score += dice1 + dice2;
  }

  return score;
}
```

// Example usage:
console.log(diceGame([[1, 2], [3, 4], [5, 6]])); // Output: 21
console.log(diceGame([[1, 1], [5, 6], [6, 4]])); // Output: 0
console.log(diceGame([[4, 5], [4, 5], [4, 5]])); // Output: 27
```

```javascript
function matrix(x, y, z) {
  const subarray = new Array(y).fill(z);
  const result = new Array(x).fill(subarray);
  return result;
}
```

// Example usage:
