```javascript
function factorChain(arr) {
  for (let i = 1; i < arr.length; i++) {
    if (arr[i] % arr[i - 1] !== 0) {
      return false;
    }
  }
  return true;
}
```

// Example usage:
console.log(factorChain([1, 2, 4, 8, 16, 32])); // Output: true
console.log(factorChain([1, 1, 1, 1, 1, 1])); // Output: true
console.log(factorChain([2, 4, 6, 7, 12])); // Output: false
console.log(factorChain([10, 1])); // Output: false
```

