function primeInRange(n1, n2) {
  for (let num = n1; num <= n2; num++) {
    if (isPrime(num)) {
      return true;
    }
  }
  return false;
}

// Helper function to check if a number is prime
function isPrime(num) {
  if (num < 2) {
    return false;
  }
  for (let i = 2; i <= Math.sqrt(num); i++) {
    if (num % i === 0) {
      return false;
    }
  }
  return true;
}
```

// Example usage:
console.log(primeInRange(10, 15)); // Output: true
console.log(primeInRange(62, 66)); // Output: false
console.log(primeInRange(3, 5)); // Output: true
```

